<h1>Artigos</h1><form method="post" class="row g-2 quick-form mb-4"><div class="col-md-3"><input class="form-control" name="name" placeholder="Nome" required></div><div class="col-md-4"><input class="form-control" name="designation" placeholder="Designação" required></div><div class="col-md-2"><input class="form-control" name="unit" placeholder="Unidade" required></div><div class="col-md-2"><input class="form-control" name="weighted_price" type="number" step="0.01" placeholder="P. ponderado" required></div><div class="col-md-1"><button class="btn btn-primary w-100">+</button></div></form><div class="table-responsive"><table class="table"><tr><th>Nome</th><th>Designação</th><th>Un.</th><th>P. Ponderado</th><th></th></tr><?php foreach($rows as $r): ?><tr><td><?= htmlspecialchars($r['name']) ?></td><td><?= htmlspecialchars($r['designation']) ?></td><td><?= htmlspecialchars($r['unit']) ?></td><td>€ <?= number_format((float)$r['weighted_price'],2,',','.') ?></td><td><a class="btn btn-sm btn-outline-danger" href="/?page=items&delete=<?= $r['id'] ?>">Apagar</a></td></tr><?php endforeach; ?></table></div>
